import json
import base64
import hmac
import hashlib
import secrets

# Generate a secret key for signing
SECRET_KEY = secrets.token_bytes(32)

def generate_session_cookie(user_obj):
    """Generate a secure session cookie"""
    session_data = json.dumps(user_obj).encode('utf-8')
    signature = hmac.new(SECRET_KEY, session_data, hashlib.sha256).digest()
    return base64.b64encode(session_data + signature).decode('utf-8')

def load_user_session(request_payload):
    """Load user session from request payload"""
    try:
        data = json.loads(request_payload)
        session_cookie = data.get("session_data")

        if not session_cookie:
            return {"status": "error", "message": "Missing session data"}

        # Validate session cookie
        try:
            decoded_data = base64.b64decode(session_cookie)
            session_data = decoded_data[:-32]  # Separate signature from data
            signature = decoded_data[-32:]  # Get signature
            expected_signature = hmac.new(SECRET_KEY, session_data, hashlib.sha256).digest()
            if not hmac.compare_digest(signature, expected_signature):
                return {"status": "error", "message": "Invalid session signature"}
        except (base64.binascii.Error, ValueError):
            return {"status": "error", "message": "Invalid session cookie"}

        # Load session data
        try:
            user_obj = json.loads(session_data.decode('utf-8'))
            return {
                "status": "success",
                "data": user_obj.get("username", "Unknown")
            }
        except json.JSONDecodeError:
            return {"status": "error", "message": "Invalid session data"}

    except json.JSONDecodeError:
        return {"status": "error", "message": "Invalid request payload"}

    except Exception as e:
        return {"status": "error", "message": str(e)}
